404	    // this single value into creator_profiles.instagram_avg_views_last_10
405	    // and bumps metrics_fetched_at.
406	    let avgViewsLast10: number | null = null;
407	    if (items) {
408	      avgViewsLast10 = meanInstagramVideoViews(items as InstagramPostItem[]);
409	    }
410	    const { data, error } = await supabase.rpc(
411	      rpcName,
412	      {
413	        p_run_id: runId,
414	        p_social_link_id: socialLinkId,
415	        p_status: nextStatus,
416	        p_fetched_at: fetchedAt,
417	        p_avg_views_last_10: avgViewsLast10,
418	        p_raw_payload: rawPayload as never,
419	        p_error_message: errorMessage,
420	      },
421	    );
422	    result = data as PersistResult | null;
423	    rpcError = error;
424	  }
425	
426	  if (rpcError) {
427	    console.error(`${rpcName} rpc error`, {
428	      run_id: runId,
429	      code: rpcError.code,
430	      message: rpcError.message,
431	    });
432	    return jsonResponse(500, { error: "DB_ERROR" });
433	  }
434	
435	  return jsonResponse(200, {
436	    ok: true,
437	    inserted: result?.inserted === true,
438	    duplicate: result?.duplicate === true,
439	  });
