  return diff === 0;
}

function verifyWebhookSecret(req: Request): boolean {
  const provided = req.headers.get("x-apify-webhook-secret");
  if (!isNonEmptyString(provided)) return false;
  const current = Deno.env.get("APIFY_WEBHOOK_SECRET") ?? "";
  const previous = Deno.env.get("APIFY_WEBHOOK_SECRET_PREVIOUS") ?? "";
  if (!current && !previous) return false;
  // Both comparisons always run (no short-circuit) so an attacker who has
  // recovered `current` can't time-distinguish whether `previous` is set.
  const matchCurrent = current ? timingSafeEqual(provided, current) : false;
  const matchPrevious = previous ? timingSafeEqual(provided, previous) : false;
  return matchCurrent || matchPrevious;
}

function validResource(value: unknown): value is ApifyResource {
  if (!value || typeof value !== "object") return false;
  const r = value as Record<string, unknown>;
  return (
    isNonEmptyString(r.id) &&
    isNonEmptyString(r.defaultDatasetId) &&
    isNonEmptyString(r.status) &&
    isNonEmptyString(r.actId)
  );
}

function meanPlayCount(items: TikTokItem[]): number | null {
  const slice = items.slice(0, 10);
  const views: number[] = [];
  for (const it of slice) {
    if (typeof it?.playCount === "number" && Number.isFinite(it.playCount)) {
      views.push(it.playCount);
    }
  }
  if (views.length === 0) return null;
  const sum = views.reduce((acc, n) => acc + n, 0);
  return Math.round(sum / views.length);
}

// Per spec §3c: filter posts to type === "Video", pick videoPlayCount with
// videoViewCount as fallback, return null if zero videos so the UI can surface
// "Not enough video posts to compute". The Apify actor input caps results at
// 10, so no slice is needed here.
function meanInstagramVideoViews(items: InstagramPostItem[]): number | null {
  const views: number[] = [];
  for (const it of items) {
    if (it?.type !== "Video") continue;
    const candidate = typeof it.videoPlayCount === "number" &&
        Number.isFinite(it.videoPlayCount)
      ? it.videoPlayCount
      : (typeof it.videoViewCount === "number" &&
          Number.isFinite(it.videoViewCount)
        ? it.videoViewCount
        : null);
    if (candidate !== null) views.push(candidate);
  }
  if (views.length === 0) return null;
  const sum = views.reduce((acc, n) => acc + n, 0);
  return Math.round(sum / views.length);
}

async function fetchDatasetItems(
  datasetId: string,
  apifyKey: string,
): Promise<unknown[]> {
  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
  url.searchParams.set("token", apifyKey);
  url.searchParams.set("clean", "1");
  const res = await fetch(url.toString(), { method: "GET" });
  if (!res.ok) {
    // Don't include res body — Apify can echo the token-carrying URL inside
    // error payloads, and this lands in edge-function logs.
    throw new Error(
      `Apify dataset '${datasetId}' fetch failed: ${res.status} ${res.statusText}`,
    );
  }
  const items = await res.json();
  if (!Array.isArray(items)) {
    throw new Error(`Apify dataset '${datasetId}' returned non-array payload`);
  }
  return items;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  if (!verifyWebhookSecret(req)) {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }

  let body: WebhookBody;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  if (
    !isNonEmptyString(body.eventType) ||
    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
    !validResource(body.resource) ||
    !isNonEmptyString(body.social_link_id) ||
    !isNonEmptyString(body.scrape_mode) ||
    !isNonEmptyString(body.run_id)
  ) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  const scrapeMode = body.scrape_mode as ScrapeMode;
  if (
    scrapeMode !== "tiktok_profile" &&
    scrapeMode !== "ig_details" &&
    scrapeMode !== "ig_posts"
  ) {
    // Unknown scrape_mode: return 200 so Apify does not retry. The row stays
    // 'refreshing' until the fail-stuck-refreshing cron janitor
    // (docs/tech-architecture.md §15) flips it to 'failed'.
    return jsonResponse(200, { ok: true, skipped: "unsupported_scrape_mode" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const resource = body.resource as ApifyResource;
  const runId = body.run_id;
  const socialLinkId = body.social_link_id;
  const fetchedAt = isNonEmptyString(body.apify_finished_at)
    ? body.apify_finished_at
    : new Date().toISOString();

  let nextStatus: MetricStatus;
  let items: unknown[] | null = null;
  let rawPayload: unknown = null;
  let errorMessage: string | null = null;

  if (body.eventType === SUCCEEDED_EVENT) {
    const apifyKey = Deno.env.get("APIFY_KEY");
    if (!apifyKey) {
      return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
    }
    try {
      items = await fetchDatasetItems(resource.defaultDatasetId, apifyKey);
    } catch (err) {
      console.error("apify dataset fetch failed", {
        run_id: runId,
        dataset_id: resource.defaultDatasetId,
        error: err instanceof Error ? err.message : String(err),
      });
      return jsonResponse(500, { error: "APIFY_FETCH_ERROR" });
    }
    rawPayload = items;
    nextStatus = "fresh";
  } else {
    nextStatus = "failed";
    errorMessage = `apify_${body.eventType.toLowerCase().replace(/\./g, "_")}`;
    rawPayload = { resource, eventType: body.eventType };
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  // Single source of truth for the RPC name per branch — used both as the
  // .rpc() call argument and in the error-log context, so the two stay in
  // sync if either side is renamed.
  const rpcName = scrapeMode === "tiktok_profile"
    ? "apify_webhook_persist_tiktok_profile"
    : scrapeMode === "ig_details"
    ? "apify_webhook_persist_ig_details"
    : "apify_webhook_persist_ig_posts";

  let result: PersistResult | null = null;
  let rpcError: { code?: string; message?: string } | null = null;

  if (scrapeMode === "tiktok_profile") {
    let followerCount: number | null = null;
    let followingCount: number | null = null;
    let totalLikes: number | null = null;
    let videoCount: number | null = null;
    let avgViewsLast10: number | null = null;
    let isVerified: boolean | null = null;
    if (items) {
      const tiktokItems = items as TikTokItem[];
      const first = tiktokItems[0];
      const authorMeta = first?.authorMeta;
      if (authorMeta) {
        followerCount = typeof authorMeta.fans === "number" ? authorMeta.fans : null;
        followingCount = typeof authorMeta.following === "number"
          ? authorMeta.following
          : null;
        totalLikes = typeof authorMeta.heart === "number" ? authorMeta.heart : null;
        videoCount = typeof authorMeta.video === "number" ? authorMeta.video : null;
        isVerified = typeof authorMeta.verified === "boolean"
          ? authorMeta.verified
          : null;
      }
      avgViewsLast10 = meanPlayCount(tiktokItems);
    }
    const { data, error } = await supabase.rpc(
      rpcName,
      {
        p_run_id: runId,
        p_social_link_id: socialLinkId,
        p_status: nextStatus,
        p_fetched_at: fetchedAt,
        p_follower_count: followerCount,
        p_following_count: followingCount,
        p_total_likes: totalLikes,
        p_video_count: videoCount,
        p_avg_views_last_10: avgViewsLast10,
        p_is_verified: isVerified,
        p_raw_payload: rawPayload as never,
        p_error_message: errorMessage,
      },
    );
    result = data as PersistResult | null;
    rpcError = error;
  } else if (scrapeMode === "ig_details") {
    // ig_details — details[0] yields follower/following/posts/verified per
    // docs/tech-architecture.md §3c. avg_views_last_10 is owned by ig_posts,
    // so leave it NULL here; the denorm trigger for ig_details updates only
    // instagram_follower_count + instagram_media_count + metrics_fetched_at.
    let followerCount: number | null = null;
    let followingCount: number | null = null;
    let mediaCount: number | null = null;
    let isVerified: boolean | null = null;
    if (items) {
      const igItems = items as InstagramDetailsItem[];
      const first = igItems[0];
      if (first) {
        followerCount = typeof first.followersCount === "number"
          ? first.followersCount
          : null;
        followingCount = typeof first.followsCount === "number"
          ? first.followsCount
          : null;
        mediaCount = typeof first.postsCount === "number"
          ? first.postsCount
          : null;
        isVerified = typeof first.verified === "boolean"
          ? first.verified
          : null;
      }
    }
    const { data, error } = await supabase.rpc(
      rpcName,
      {
        p_run_id: runId,
        p_social_link_id: socialLinkId,
        p_status: nextStatus,
        p_fetched_at: fetchedAt,
        p_follower_count: followerCount,
        p_following_count: followingCount,
        p_media_count: mediaCount,
        p_is_verified: isVerified,
        p_raw_payload: rawPayload as never,
        p_error_message: errorMessage,
      },
    );
    result = data as PersistResult | null;
    rpcError = error;
  } else {
    // ig_posts — only avg_views_last_10 is owned here (spec §4.7
    // column-ownership comments). The denorm trigger for ig_posts mirrors
    // this single value into creator_profiles.instagram_avg_views_last_10
    // and bumps metrics_fetched_at.
    let avgViewsLast10: number | null = null;
    if (items) {
      avgViewsLast10 = meanInstagramVideoViews(items as InstagramPostItem[]);
    }
    const { data, error } = await supabase.rpc(
      rpcName,
      {
        p_run_id: runId,
        p_social_link_id: socialLinkId,
        p_status: nextStatus,
        p_fetched_at: fetchedAt,
        p_avg_views_last_10: avgViewsLast10,
        p_raw_payload: rawPayload as never,
        p_error_message: errorMessage,
      },
    );
    result = data as PersistResult | null;
    rpcError = error;
  }

  if (rpcError) {
    console.error(`${rpcName} rpc error`, {
      run_id: runId,
      code: rpcError.code,
      message: rpcError.message,
    });
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  return jsonResponse(200, {
    ok: true,
    inserted: result?.inserted === true,
    duplicate: result?.duplicate === true,
  });
});

### 3d. Client Pattern

```ts
import { ApifyClient } from 'apify-client';
const apify = new ApifyClient({ token: Deno.env.get('APIFY_TOKEN')! });

// --- synchronous short-run (used on first signup — user is waiting) ---
const tiktok = await apify
  .actor('clockworks/tiktok-scraper')
  .call(
    {
      profiles: [handle],
      resultsPerPage: 10,
      profileScrapeSections: ['videos'],
      profileSorting: 'latest',
      excludePinnedPosts: true,
      shouldDownloadVideos: false,
      shouldDownloadCovers: false,
    },
    { waitSecs: 60 },
  );
const { items: tiktokItems } = await apify.dataset(tiktok.defaultDatasetId).listItems();

// --- async run with webhook (used for cron refresh and initial IG scrapes) ---
const run = await apify
  .actor('apify/instagram-scraper')
  .start(
    {
      directUrls: [`https://www.instagram.com/${handle}/`],
      resultsType: 'details',
      resultsLimit: 1,
    },
    {
      webhooks: [{
        eventTypes: ['ACTOR.RUN.SUCCEEDED', 'ACTOR.RUN.FAILED', 'ACTOR.RUN.TIMED_OUT', 'ACTOR.RUN.ABORTED'],
        requestUrl: `${SUPABASE_URL}/functions/v1/webhooks-apify`,
        payloadTemplate: JSON.stringify({
          social_link_id: '<id>',
          scrape_mode: 'ig_details',       // or 'ig_posts' | 'tiktok_profile'
          run_id: '{{resource.id}}',
          status: '{{resource.status}}',
          dataset_id: '{{resource.defaultDatasetId}}',
        }),
        headersTemplate: JSON.stringify({
          'X-Apify-Webhook-Secret': Deno.env.get('APIFY_WEBHOOK_SECRET')!,
        }),
      }],
    },
  );
```

**Signup flow (user waiting):** Use sync `.call(input, { waitSecs: 60 })` for the *first* scrape per handle. If the actor finishes inside 60s, populate the snapshot inline; if it doesn't, the `waitSecs` limit returns a `RUNNING` run and the webhook completes it later. UI shows "Fetching your metrics..." until either returns.

**Cron refresh / manual refresh:** Always async (`.start()` with webhook). The refresh endpoint queues work and returns `202 Accepted` immediately.

### 3e. Metric Derivation — Summary

| Denormalized field on `creator_profiles` | TikTok source | Instagram source |
|---|---|---|
| `tiktok_follower_count` | `authorMeta.fans` | — |
| `tiktok_avg_views_last_10` | `mean(playCount[:10])` | — |
| `tiktok_video_count` | `authorMeta.video` | — |
| `tiktok_is_verified` | `authorMeta.verified` | — |
| `instagram_follower_count` | — | `details[0].followersCount` |
| `instagram_avg_views_last_10` | — | `mean(videoPlayCount ?? videoViewCount)` across `type === "Video"` posts |
| `instagram_media_count` | — | `details[0].postsCount` |
| `instagram_is_verified` | — | `details[0].verified` *(reserved; column add in v1.1)* |

Stored fully in `metric_snapshots.raw_payload` (jsonb) for forensics and future backfills — if we later need `diggCount` trends we don't need to re-scrape.

### 3f. Cost & Rate Management

- Every actor run costs Apify credits. Published pricing at time of writing: TikTok Scraper ≈ $0.40 / 1k videos (so ~$0.004 per 10-video run), Instagram Scraper ≈ $2.30 / 1k results. Budget conservatively at ~$0.01 per TikTok refresh and ~$0.02 per IG refresh (details + 10 posts = 11 results).
- **Scale math (back-of-envelope):** 10k creators × daily cron refresh ≈ $40/day TikTok-only, $200/day IG-only, $240/day fully-linked. That's ~$7.2k/month worst case. Sensitivity: cutting daily cron to every 48h halves that; capping free-tier creators to weekly refresh quarters it.
- **Hard throttle:** `metrics/refresh` server-side limit 1 per 6h per `(user, platform)`. `429` returned before any Apify call.
- **Daily cron enforcement:** `cron-refresh-metrics` edge function pulls `social_links` ordered by `metrics_fetched_at ASC NULLS FIRST` and keeps a running tally of `estimated_cost_usd`; it stops dispatching new runs once `estimated_cost_usd >= APIFY_DAILY_BUDGET_USD`. Skipped links get picked up first the next day because of the `NULLS FIRST` ordering and oldest-first tie-break. Estimate is static per `scrape_mode` (`tiktok_profile`: $0.005, `ig_details`: $0.005, `ig_posts`: $0.015) — no dynamic pricing lookup needed.
- Set Apify run timeout (via `timeoutSecs` input to `.start()`) to 120s; if actor hangs, we fail-close the snapshot (`status=failed`) and retry on next cron window.
- Memory: default `memoryMbytes` is fine for both actors (1024 MB); don't override.

