118	// Constant-time string compare. Lengths are compared first; when lengths
119	// differ we still iterate over the longer string to keep timing flat.
120	function timingSafeEqual(a: string, b: string): boolean {
121	  const enc = new TextEncoder();
122	  const aBytes = enc.encode(a);
123	  const bBytes = enc.encode(b);
124	  const len = Math.max(aBytes.length, bBytes.length);
125	  let diff = aBytes.length ^ bBytes.length;
126	  for (let i = 0; i < len; i++) {
127	    const ac = i < aBytes.length ? aBytes[i] : 0;
128	    const bc = i < bBytes.length ? bBytes[i] : 0;
129	    diff |= ac ^ bc;
