// Edge function: auth-signup-creator (US-019 + US-020)
//
// Contract:
//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
//     → 200 {
//         token: string,
//         user_id: string,
//         role: 'creator',
//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
//       }
//       where Status is 'fresh' | 'refreshing' | 'failed'.
//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
//     → 422 { error: 'HANDLE_REQUIRED' }
//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
//
// Auth: none. This is how a creator obtains their first JWT, so the
// endpoint is verify_jwt=false at the gateway. The handler itself mints
// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
//
// Atomicity: the users + creator_profiles + social_links inserts run
// inside a single Postgres transaction via the public.auth_signup_creator
// RPC (us_019 migration). A failure on any insert rolls back the flow.
// Apify dispatch happens AFTER the RPC commits — per spec §5.1, a
// dispatch failure does NOT roll back the account (the user gets their
// JWT, metrics_status carries the per-platform outcome so the client can
// decide whether to retry later or surface a 'refreshing' placeholder).
//
// Handle normalization: leading '@' is stripped and whitespace trimmed
// before the RPC call. Handles are compared case-insensitively (citext),
// matching social_links.handle's column type.
//
// Apify dispatch (US-020): once the RPC commits, we look up the
// freshly-inserted social_links rows, then kick one or more Apify runs in
// parallel via Promise.allSettled — tiktok_profile for TikTok handles;
// ig_details and ig_posts for Instagram handles. Each run is registered
// with a per-run webhook pointing back at /functions/v1/apify-webhook so
// the receiver can persist the metric_snapshots row when Apify finishes.
// The wait window is APIFY_WAIT_SECS (60s); runs that come back
// SUCCEEDED within the window are reported as 'fresh' (the webhook will
// also arrive and be deduped via the unique index on run_id), otherwise
// 'refreshing' and the client polls. A thrown dispatch is 'failed'.
//
// Pre-refreshing rows: the spec calls for pre-creating metric_snapshots
// rows in status='refreshing' before the scrape so the client has
// something to read. That's deferred — the existing US-016..US-018 RPCs
// INSERT on webhook arrival via ON CONFLICT DO NOTHING, so the row
// appears only once Apify finishes. Tracked as a spec gap in progress.txt.
//
// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
// via a signup_attempts table (does not yet exist). Same status as the
// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.

import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2";
import { signJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";
import {
  type ApifyRunResult,
  type ApifyWebhookSpec,
  runInstagramDetails,
  runInstagramPosts,
  runTikTokProfile,
} from "../_shared/apify.ts";

const APIFY_WAIT_SECS = 60;
const APIFY_TERMINAL_EVENTS = [
  "ACTOR.RUN.SUCCEEDED",
  "ACTOR.RUN.FAILED",
  "ACTOR.RUN.TIMED_OUT",
  "ACTOR.RUN.ABORTED",
];

type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
type MetricsStatus = "fresh" | "refreshing" | "failed";

interface SignupRequest {
  username?: unknown;
  tiktok_handle?: unknown;
  instagram_handle?: unknown;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function isString(value: unknown): value is string {
  return typeof value === "string";
}

function normalizeHandle(value: unknown): string | null {
  if (!isString(value)) return null;
  const stripped = value.trim().replace(/^@+/, "").trim();
  return stripped.length > 0 ? stripped : null;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  let body: SignupRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const username =
    isString(body.username) && body.username.trim().length > 0
      ? body.username.trim()
      : null;
  const tiktokHandle = normalizeHandle(body.tiktok_handle);
  const instagramHandle = normalizeHandle(body.instagram_handle);

  if (!username) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }
  if (!tiktokHandle && !instagramHandle) {
    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data, error } = await supabase.rpc("auth_signup_creator", {
    p_username: username,
    p_tiktok_handle: tiktokHandle,
    p_instagram_handle: instagramHandle,
  });

  if (error) {
    console.error("auth_signup_creator rpc error", error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const result = data as { user_id?: string; error?: string } | null;
  if (result?.error === "USERNAME_TAKEN") {
    return jsonResponse(409, { error: "USERNAME_TAKEN" });
  }
  if (result?.error === "HANDLE_TAKEN") {
    return jsonResponse(409, { error: "HANDLE_TAKEN" });
  }
  if (!result?.user_id) {
    console.error("auth_signup_creator returned unexpected shape", result);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const userId = result.user_id;
  const sessionId = crypto.randomUUID();
  let token: string;
  try {
    token = await signJwt({
      sub: userId,
      role: "creator",
      session_id: sessionId,
    });
  } catch (err) {
    console.error("signJwt failed", err);
    return jsonResponse(500, { error: "JWT_ERROR" });
  }

  const metricsStatus = await dispatchApifyRuns({
    supabase,
    supabaseUrl,
    userId,
    tiktokHandle,
    instagramHandle,
  });

  return jsonResponse(200, {
    token,
    user_id: userId,
    role: "creator",
    metrics_status: metricsStatus,
  });
});

// Dispatches the Apify runs required for the freshly-created creator
// account. Returns a partial metrics_status map keyed by platform. If
// APIFY_KEY or APIFY_WEBHOOK_SECRET is unset (e.g. local dev without
// Apify credentials), logs a warning and returns {} — the account is
// still usable, the client just won't see any metrics until a future
// scrape picks it up. A failure to dispatch a single platform does not
// affect the others.
// deno-lint-ignore no-explicit-any -- supabase-js generic args differ between
// the createClient call above (inferred as public schema) and any helper
// import; typing this parameter loosely avoids a widening mismatch.
async function dispatchApifyRuns(params: {
  supabase: SupabaseClient<any, any, any>;
  supabaseUrl: string;
  userId: string;
  tiktokHandle: string | null;
  instagramHandle: string | null;
}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
  const { supabase, supabaseUrl, userId, tiktokHandle, instagramHandle } =
    params;
  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};

  const apifyKey = Deno.env.get("APIFY_KEY");
  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
  if (!apifyKey || !webhookSecret) {
    console.warn(
      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
    );
    return metricsStatus;
  }

  const { data: links, error: linksError } = await supabase
    .from("social_links")
    .select("id,platform")
    .eq("user_id", userId);
  if (linksError) {
    console.error("social_links lookup failed", linksError);
    return metricsStatus;
  }

  const linkRows = (links ?? []) as Array<{ id: string; platform: string }>;
  const tiktokLinkId = linkRows.find((l) => l.platform === "tiktok")?.id;
  const igLinkId = linkRows.find((l) => l.platform === "instagram")?.id;

  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
  const buildWebhook = (
    linkId: string,
    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
  ): ApifyWebhookSpec => ({
    eventTypes: APIFY_TERMINAL_EVENTS,
    requestUrl: webhookUrl,
    // Apify's template substitution rule: when a JSON string value contains
    // ONLY a single placeholder (e.g. "{{resource}}"), the placeholder is
    // replaced with the raw JSON value — including objects. That lets us
    // forward the full run resource in-place without enumerating every
    // field. apify-webhook/index.ts validResource only needs id,
    // defaultDatasetId, status, and actId; we pull them all from resource.
    payloadTemplate: JSON.stringify({
      eventType: "{{eventType}}",
      resource: "{{resource}}",
      social_link_id: linkId,
      scrape_mode: scrapeMode,
      run_id: "{{resource.id}}",
      dataset_id: "{{resource.defaultDatasetId}}",
    }),
    headersTemplate: JSON.stringify({
      "X-Apify-Webhook-Secret": webhookSecret,
    }),
  });

  interface Task {
    key: MetricsKey;
    run: () => Promise<ApifyRunResult>;
  }
  const tasks: Task[] = [];
  if (tiktokHandle && tiktokLinkId) {
    tasks.push({
      key: "tiktok",
      run: () =>
        runTikTokProfile(tiktokHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(tiktokLinkId, "tiktok_profile")],
        }),
    });
  }
  if (instagramHandle && igLinkId) {
    tasks.push({
      key: "ig_details",
      run: () =>
        runInstagramDetails(instagramHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(igLinkId, "ig_details")],
        }),
    });
    tasks.push({
      key: "ig_posts",
      run: () =>
        runInstagramPosts(instagramHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(igLinkId, "ig_posts")],
        }),
    });
  }

  if (tasks.length === 0) return metricsStatus;

  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
  settled.forEach((outcome, i) => {
    const key = tasks[i].key;
    if (outcome.status === "fulfilled") {
      // Apify returns status=SUCCEEDED when the run completed inside
      // the wait window, otherwise RUNNING (the webhook will complete
      // it later). Anything terminal-but-not-succeeded we treat as
      // 'failed' — the webhook receiver will also write the failed row.
      const s = outcome.value.status;
      metricsStatus[key] = s === "SUCCEEDED"
        ? "fresh"
        : s === "RUNNING" || s === "READY"
        ? "refreshing"
        : "failed";
    } else {
      console.error(`apify ${key} dispatch failed`, outcome.reason);
      metricsStatus[key] = "failed";
    }
  });

  return metricsStatus;
}

// Live end-to-end for auth-signup-creator → Apify dispatch (US-020).
//
// Usage: bun run scripts/test/auth-signup-creator-live.ts
// Requires SUPABASE_URL, SUPABASE_ANON_KEY, and ideally
// SUPABASE_SERVICE_ROLE_KEY (for cleanup). Burns a few cents of Apify
// credits — NOT part of the default smoke suite.
//
// Uses a stable public TikTok handle (`tiktok`) and Instagram handle
// (`nasa`) so the Apify runs return real datasets. Within the 60s wait
// window the edge function should see all three runs SUCCEED, emit the
// webhooks, and the webhook receiver should write metric_snapshots rows
// keyed on the social_links created by the signup.
//
// Assertions:
//   1. Response 200 with metrics_status.tiktok, ig_details, ig_posts
//      all 'fresh' (all three ran to completion within waitSecs=60)
//   2. After a short settle delay, one metric_snapshots row per platform
//      exists in status='fresh' keyed on the freshly-minted social_links.

const {
  SUPABASE_URL,
  SUPABASE_ANON_KEY,
  SUPABASE_SERVICE_ROLE_KEY,
} = process.env;

if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
  console.error("SUPABASE_URL and SUPABASE_ANON_KEY required in .env");
  process.exit(1);
}

const unique = Date.now();
const primary = {
  username: `us020_live_${unique}`,
  tiktok_handle: "tiktok",
  instagram_handle: "nasa",
};

const endpoint = `${SUPABASE_URL}/functions/v1/auth-signup-creator`;

console.log(`POST ${endpoint} with handles tiktok=${primary.tiktok_handle}, instagram=${primary.instagram_handle}`);
const signup = await fetch(endpoint, {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
    apikey: SUPABASE_ANON_KEY,
  },
  body: JSON.stringify(primary),
});
const signupBody = await signup.json();
console.log("signup:", signup.status, signupBody);

if (signup.status !== 200) {
  console.error("signup did not return 200");
  process.exit(1);
}

const metricsStatus = signupBody?.metrics_status as
  | Record<string, string>
  | undefined;
if (!metricsStatus) {
  console.error("metrics_status missing from response");
  process.exit(1);
}
for (const key of ["tiktok", "ig_details", "ig_posts"]) {
  if (!metricsStatus[key]) {
    console.error(`metrics_status.${key} missing — is APIFY_KEY set on the deployed function?`);
    process.exit(1);
  }
}
console.log("metrics_status:", metricsStatus);
if (
  metricsStatus.tiktok !== "fresh" ||
  metricsStatus.ig_details !== "fresh" ||
  metricsStatus.ig_posts !== "fresh"
) {
  console.warn(
    "warn: at least one platform is not 'fresh' — this can happen under heavy load; proceeding to DB check anyway",
  );
}

const userId = signupBody.user_id as string;

// Give the webhook → RPC path a moment to land (the dispatch returned
// synchronously but the webhook is an independent HTTP round-trip).
await new Promise((r) => setTimeout(r, 4000));

if (!SUPABASE_SERVICE_ROLE_KEY) {
  console.log(
    "SUPABASE_SERVICE_ROLE_KEY not set — skipping DB assertions + cleanup",
  );
  console.log("ok (response-level only) — user_id:", userId);
  process.exit(0);
}

const pgrst = (path: string, init: RequestInit = {}) =>
  fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    ...init,
    headers: {
      apikey: SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
      "Content-Type": "application/json",
      ...(init.headers ?? {}),
    },
  });

const linksRes = await pgrst(
  `social_links?user_id=eq.${userId}&select=id,platform`,
);
if (!linksRes.ok) {
  console.error("social_links lookup failed:", linksRes.status, await linksRes.text());
  process.exit(1);
}
const links = (await linksRes.json()) as Array<{ id: string; platform: string }>;
console.log("social_links:", links);

const snapRes = await pgrst(
  `metric_snapshots?social_link_id=in.(${
    links.map((l) => l.id).join(",")
  })&select=id,social_link_id,scrape_mode,status,apify_run_id`,
);
if (!snapRes.ok) {
  console.error("metric_snapshots lookup failed:", snapRes.status, await snapRes.text());
  process.exit(1);
}
const snaps = (await snapRes.json()) as Array<{
  id: string;
  social_link_id: string;
  scrape_mode: string;
  status: string;
  apify_run_id: string;
}>;
console.log("metric_snapshots:", snaps);

// Require one row per scrape_mode, status=fresh. The webhook may still
// be in-flight so retry up to 3 times over ~15s.
const required = new Set(["tiktok_profile", "ig_details", "ig_posts"]);
let attempts = 0;
let current = snaps;
while (attempts < 3) {
  const modes = new Set(current.map((s) => s.scrape_mode));
  if ([...required].every((m) => modes.has(m))) break;
  attempts += 1;
  console.log(`waiting for webhook-driven snapshots... attempt ${attempts}`);
  await new Promise((r) => setTimeout(r, 5000));
  const retryRes = await pgrst(
    `metric_snapshots?social_link_id=in.(${
      links.map((l) => l.id).join(",")
    })&select=id,social_link_id,scrape_mode,status,apify_run_id`,
  );
  current = (await retryRes.json()) as typeof snaps;
}

const got = new Set(current.map((s) => s.scrape_mode));
for (const mode of required) {
  if (!got.has(mode)) {
    console.error(`missing metric_snapshots row for scrape_mode=${mode}`);
    process.exit(1);
  }
}
for (const s of current) {
  if (s.status !== "fresh") {
    console.warn(`warn: snapshot ${s.scrape_mode} status=${s.status} (expected 'fresh')`);
  }
}

console.log("ok — live e2e completed. cleaning up...");
const cleanup = await pgrst(`users?id=eq.${userId}`, { method: "DELETE" });
if (!cleanup.ok) {
  console.warn("cleanup failed (non-fatal):", cleanup.status, await cleanup.text());
} else {
  console.log("cleaned up test user");
}

// Smoke test for the deployed auth-signup-creator edge function.
//
// Usage: bun run scripts/test/auth-signup-creator.ts
// Requires SUPABASE_URL and SUPABASE_ANON_KEY in .env (bun auto-loads).
//
// Note (US-020): the happy-path call dispatches real Apify runs against
// the supplied handles. The handles used below are synthetic, so Apify
// will return empty/failed results — but it still burns a small amount
// of credits (~$0.08 per smoke run). If you need handle-level dataset
// content, use scripts/test/auth-signup-creator-live.ts instead.
//
// Asserts:
//   1. Fresh { username, tiktok_handle, instagram_handle } → 200 with
//      { token, user_id, role:'creator', metrics_status:{tiktok, ig_details, ig_posts} }
//   2. Same body → 409 USERNAME_TAKEN
//   3. Fresh username + no handles → 422 HANDLE_REQUIRED
//   4. Fresh username + missing body field → 400 INVALID_REQUEST
//   5. Fresh username + recycled tiktok handle → 409 HANDLE_TAKEN
//   6. Normalized handle: leading '@' is stripped (verified by reusing the
//      naked handle against a row created with the '@'-prefixed form)

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
if (!supabaseUrl || !anonKey) {
  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
  process.exit(1);
}

const endpoint = `${supabaseUrl}/functions/v1/auth-signup-creator`;
const baseHeaders = {
  "Content-Type": "application/json",
  Authorization: `Bearer ${anonKey}`,
  apikey: anonKey,
};

const unique = Date.now();
const primary = {
  username: `us019_test_${unique}`,
  tiktok_handle: `us019_tt_${unique}`,
  instagram_handle: `us019_ig_${unique}`,
};

async function post(body: unknown) {
  const res = await fetch(endpoint, {
    method: "POST",
    headers: baseHeaders,
    body: JSON.stringify(body),
  });
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

const first = await post(primary);
console.log("first:", first.status, first.data);
if (first.status !== 200) process.exit(1);
if (
  typeof first.data?.token !== "string" ||
  typeof first.data?.user_id !== "string" ||
  first.data?.role !== "creator"
) {
  console.error("unexpected 200 body shape");
  process.exit(1);
}

// US-020: metrics_status must exist as an object. When APIFY_KEY /
// APIFY_WEBHOOK_SECRET are configured on the deployed function (the
// expected prod + staging case) it should carry one entry per platform
// dispatched — tiktok + ig_details + ig_posts for a dual-handle signup.
// When those env vars are absent, the function logs a warn and returns
// an empty object. We accept both shapes here, but require the keys to
// be populated if any are present.
const metricsStatus = first.data?.metrics_status;
if (metricsStatus == null || typeof metricsStatus !== "object") {
  console.error("metrics_status missing or not an object");
  process.exit(1);
}
const statusValues = new Set(["fresh", "refreshing", "failed"]);
for (const key of Object.keys(metricsStatus)) {
  if (!["tiktok", "ig_details", "ig_posts"].includes(key)) {
    console.error(`unexpected metrics_status key: ${key}`);
    process.exit(1);
  }
  if (!statusValues.has(metricsStatus[key])) {
    console.error(`unexpected metrics_status[${key}] value: ${metricsStatus[key]}`);
    process.exit(1);
  }
}
if (Object.keys(metricsStatus).length > 0) {
  // If Apify was configured, all three keys should be present for a
  // dual-handle signup.
  for (const key of ["tiktok", "ig_details", "ig_posts"]) {
    if (!(key in metricsStatus)) {
      console.error(`metrics_status partially populated — missing ${key}`);
      process.exit(1);
    }
  }
  console.log("metrics_status ok:", metricsStatus);
} else {
  console.log("metrics_status empty — Apify not configured on deployed fn");
}

const second = await post(primary);
console.log("second:", second.status, second.data);
if (second.status !== 409 || second.data?.error !== "USERNAME_TAKEN") {
  console.error("expected 409 USERNAME_TAKEN");
  process.exit(1);
}

const third = await post({ username: `us019_test_nohandles_${unique}` });
console.log("third:", third.status, third.data);
if (third.status !== 422 || third.data?.error !== "HANDLE_REQUIRED") {
  console.error("expected 422 HANDLE_REQUIRED");
  process.exit(1);
}

const fourth = await post({ tiktok_handle: `us019_missinguser_${unique}` });
console.log("fourth:", fourth.status, fourth.data);
if (fourth.status !== 400 || fourth.data?.error !== "INVALID_REQUEST") {
  console.error("expected 400 INVALID_REQUEST");
  process.exit(1);
}

// Reuse the primary tiktok handle with a new username → HANDLE_TAKEN.
// Prefix with '@' to prove normalization strips it before the RPC compares.
const fifth = await post({
  username: `us019_test_handlecollide_${unique}`,
  tiktok_handle: `@${primary.tiktok_handle}`,
});
console.log("fifth:", fifth.status, fifth.data);
if (fifth.status !== 409 || fifth.data?.error !== "HANDLE_TAKEN") {
  console.error("expected 409 HANDLE_TAKEN (proves '@' normalization)");
  process.exit(1);
}

// Teardown: delete every users row this run created. social_links +
// creator_profiles cascade via ON DELETE CASCADE. We intentionally use
// the service role via PostgREST here rather than a REST call because
// the anon key can't delete from RLS-guarded tables. If the caller only
// has the anon key, we skip cleanup (CI environments should set
// SUPABASE_SERVICE_ROLE_KEY).
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
if (serviceRoleKey) {
  const cleanup = await fetch(
    `${supabaseUrl}/rest/v1/users?username=like.us019_test_${unique}*`,
    {
      method: "DELETE",
      headers: {
        apikey: serviceRoleKey,
        Authorization: `Bearer ${serviceRoleKey}`,
        "Content-Type": "application/json",
        Prefer: "return=representation",
      },
    },
  );
  if (!cleanup.ok) {
    console.warn("cleanup failed (non-fatal):", cleanup.status, await cleanup.text());
  } else {
    console.log("cleaned up test rows");
  }
} else {
  console.log("SUPABASE_SERVICE_ROLE_KEY not set — skipping cleanup");
}

console.log("ok — created user_id:", first.data.user_id);

// Unit tests for the Apify client wrapper.
//
// Replace `globalThis.fetch` with a spy, then assert each wrapper function
// constructs the correct URL (actor slug + token + waitForFinish) and POST
// body (actor input shape per docs/tech-architecture.md §3b / §3c).
//
// Run: deno test --allow-env supabase/functions/_shared/apify.test.ts

import {
  assertEquals,
  assertRejects,
} from "jsr:@std/assert@1";

import {
  runInstagramDetails,
  runInstagramPosts,
  runTikTokProfile,
} from "./apify.ts";

type Captured = { url: string; init: RequestInit };

function installFetchSpy(
  response: Record<string, unknown>,
  init: ResponseInit = { status: 201 },
): { captured: Captured[]; restore: () => void } {
  const original = globalThis.fetch;
  const captured: Captured[] = [];
  globalThis.fetch = ((input: string | URL | Request, reqInit?: RequestInit) => {
    const url = typeof input === "string"
      ? input
      : input instanceof URL
      ? input.toString()
      : input.url;
    captured.push({ url, init: reqInit ?? {} });
    return Promise.resolve(
      new Response(JSON.stringify(response), {
        status: init.status ?? 201,
        headers: { "content-type": "application/json" },
      }),
    );
    // deno-lint-ignore no-explicit-any -- fetch has many overloads; the spy matches the subset we use
  }) as any;
  return { captured, restore: () => { globalThis.fetch = original; } };
}

function stubRunResponse() {
  return {
    data: {
      id: "run_abc123",
      defaultDatasetId: "ds_xyz789",
      status: "SUCCEEDED",
    },
  };
}

function setApifyKey(value: string | null) {
  if (value === null) Deno.env.delete("APIFY_KEY");
  else Deno.env.set("APIFY_KEY", value);
}

Deno.test("runTikTokProfile builds the tiktok actor run request", async () => {
  setApifyKey("test-token");
  const { captured, restore } = installFetchSpy(stubRunResponse());
  try {
    const result = await runTikTokProfile("charlidamelio");

    assertEquals(captured.length, 1);
    const url = new URL(captured[0].url);
    assertEquals(url.origin + url.pathname,
      "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs");
    assertEquals(url.searchParams.get("token"), "test-token");
    assertEquals(url.searchParams.get("waitForFinish"), "60");

    assertEquals(captured[0].init.method, "POST");
    const headers = new Headers(captured[0].init.headers as HeadersInit);
    assertEquals(headers.get("content-type"), "application/json");

    const body = JSON.parse(captured[0].init.body as string);
    assertEquals(body, {
      profiles: ["charlidamelio"],
      resultsPerPage: 10,
      profileScrapeSections: ["videos"],
      profileSorting: "latest",
      excludePinnedPosts: true,
      shouldDownloadVideos: false,
      shouldDownloadCovers: false,
    });

    assertEquals(result, {
      runId: "run_abc123",
      datasetId: "ds_xyz789",
      status: "SUCCEEDED",
    });
  } finally {
    restore();
  }
});

