158	function meanPlayCount(items: TikTokItem[]): number | null {
159	  const slice = items.slice(0, 10);
160	  const views: number[] = [];
161	  for (const it of slice) {
162	    if (typeof it?.playCount === "number" && Number.isFinite(it.playCount)) {
