  resource?: unknown;
  social_link_id?: unknown;
  scrape_mode?: unknown;
  run_id?: unknown;
  status?: unknown;
  apify_finished_at?: unknown;
  dataset_id?: unknown;
}

interface ApifyResource {
  id: string;
  defaultDatasetId: string;
  status: string;
  actId: string;
}

interface TikTokAuthorMeta {
  fans?: number;
  following?: number;
  heart?: number;
  video?: number;
  verified?: boolean;
}

interface TikTokItem {
  authorMeta?: TikTokAuthorMeta;
  playCount?: number;
}

interface InstagramDetailsItem {
  followersCount?: number;
  followsCount?: number;
  postsCount?: number;
  verified?: boolean;
