const SUCCEEDED_EVENT = "ACTOR.RUN.SUCCEEDED";
const TERMINAL_EVENT_TYPES = new Set([
  SUCCEEDED_EVENT,
  "ACTOR.RUN.FAILED",
  "ACTOR.RUN.TIMED_OUT",
  "ACTOR.RUN.ABORTED",
