async function fetchDatasetItems(
  datasetId: string,
  apifyKey: string,
): Promise<unknown[]> {
  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
  url.searchParams.set("token", apifyKey);
  url.searchParams.set("clean", "1");
