1	// Apify client wrapper for Marketify edge functions.
2	//
3	// Contract: runTikTokProfile(handle, { waitSecs?, webhooks? })    -> { runId, datasetId, status }
4	//           runInstagramDetails(handle, { waitSecs?, webhooks? }) -> { runId, datasetId, status }
5	//           runInstagramPosts(handle, { waitSecs?, webhooks? })   -> { runId, datasetId, status }
6	// Actors:   `clockworks/tiktok-scraper` (REST slug `clockworks~tiktok-scraper`),
7	//           `apify/instagram-scraper`  (REST slug `apify~instagram-scraper`).
8	//           Actor input shapes per docs/tech-architecture.md §3b / §3c.
9	// Endpoint: POST https://api.apify.com/v2/acts/<slug>/runs?token=<key>&waitForFinish=<secs>[&webhooks=<b64>].
10	//           The waitForFinish query parameter makes Apify block up to `waitSecs`
11	//           seconds before returning the run object, so callers can either parse
12	//           results inline (status=SUCCEEDED) or fall back to webhook-completed
13	//           delivery when the wait expires (status=RUNNING).
14	// Webhooks: per-run ad-hoc webhooks are passed as base64(JSON.stringify(specs))
15	//           in the `webhooks` query param per Apify's ad-hoc webhook API
16	//           (https://docs.apify.com/platform/integrations/webhooks/ad-hoc-webhooks).
17	//           Each spec includes eventTypes, requestUrl, and optional
18	//           payloadTemplate + headersTemplate (both already JSON-stringified
19	//           by the caller per docs/tech-architecture.md §3d), plus optional
20	//           shouldInterpolateStrings (required=true when payloadTemplate
21	//           wraps `{{placeholders}}` in quotes — Apify only substitutes
22	//           quoted placeholders under that flag; bare unquoted placeholders
23	//           always substitute as raw JSON).
24	// Secret:   APIFY_KEY env var (the Apify API token).
25	// Auth:     no inbound auth requirement — this module is a building block for
26	//           edge functions that have already verified JWT.
27	
28	const APIFY_API_BASE = "https://api.apify.com/v2";
29	
30	const TIKTOK_ACTOR_SLUG = "clockworks~tiktok-scraper";
31	const INSTAGRAM_ACTOR_SLUG = "apify~instagram-scraper";
32	
33	const DEFAULT_WAIT_SECS = 60;
34	
35	export interface ApifyRunResult {
36	  runId: string;
37	  datasetId: string;
38	  status: string;
39	}
40	
41	export interface ApifyWebhookSpec {
42	  eventTypes: string[];
43	  requestUrl: string;
44	  payloadTemplate: string;
45	  headersTemplate?: string;
46	  shouldInterpolateStrings?: boolean;
47	}
48	
49	export interface ApifyRunOptions {
50	  waitSecs?: number;
51	  webhooks?: ApifyWebhookSpec[];
52	}
53	
54	function readApifyKey(): string {
55	  const k = Deno.env.get("APIFY_KEY");
56	  if (!k) throw new Error("APIFY_KEY is not set");
57	  return k;
58	}
59	
60	async function startActorRun(
61	  slug: string,
62	  input: Record<string, unknown>,
63	  waitSecs: number,
64	  webhooks?: ApifyWebhookSpec[],
65	): Promise<ApifyRunResult> {
66	  if (!Number.isFinite(waitSecs) || waitSecs < 0) {
67	    throw new Error("waitSecs must be a non-negative finite number");
68	  }
69	  const url = new URL(`${APIFY_API_BASE}/acts/${slug}/runs`);
70	  url.searchParams.set("token", readApifyKey());
71	  url.searchParams.set("waitForFinish", String(Math.floor(waitSecs)));
72	  if (webhooks && webhooks.length > 0) {
73	    url.searchParams.set("webhooks", btoa(JSON.stringify(webhooks)));
74	  }
75	
76	  const res = await fetch(url.toString(), {
77	    method: "POST",
78	    headers: { "content-type": "application/json" },
79	    body: JSON.stringify(input),
80	  });
81	
82	  if (!res.ok) {
83	    // Response body is intentionally not included — Apify sometimes echoes
84	    // the request URL (which carries the APIFY_KEY query param) inside error
85	    // payloads, and this error will land in edge-function logs.
86	    throw new Error(
87	      `Apify actor '${slug}' run failed: ${res.status} ${res.statusText}`,
88	    );
89	  }
90	
91	  const payload = (await res.json()) as {
92	    data?: { id?: string; defaultDatasetId?: string; status?: string };
93	  };
94	  const data = payload.data;
95	  if (
96	    !data ||
97	    typeof data.id !== "string" ||
98	    typeof data.defaultDatasetId !== "string" ||
99	    typeof data.status !== "string"
100	  ) {
101	    throw new Error(
102	      `Apify actor '${slug}' returned malformed run payload`,
103	    );
104	  }
105	  return {
106	    runId: data.id,
107	    datasetId: data.defaultDatasetId,
108	    status: data.status,
109	  };
110	}
111	
112	export async function runTikTokProfile(
113	  handle: string,
114	  options: ApifyRunOptions = {},
115	): Promise<ApifyRunResult> {
116	  if (!handle) throw new Error("handle is required");
117	  return await startActorRun(
118	    TIKTOK_ACTOR_SLUG,
119	    {
120	      profiles: [handle],
121	      resultsPerPage: 10,
122	      profileScrapeSections: ["videos"],
123	      profileSorting: "latest",
124	      excludePinnedPosts: true,
125	      shouldDownloadVideos: false,
126	      shouldDownloadCovers: false,
127	    },
128	    options.waitSecs ?? DEFAULT_WAIT_SECS,
129	    options.webhooks,
130	  );
131	}
132	
133	export async function runInstagramDetails(
134	  handle: string,
135	  options: ApifyRunOptions = {},
136	): Promise<ApifyRunResult> {
137	  if (!handle) throw new Error("handle is required");
138	  return await startActorRun(
139	    INSTAGRAM_ACTOR_SLUG,
140	    {
141	      directUrls: [`https://www.instagram.com/${handle}/`],
142	      resultsType: "details",
143	      resultsLimit: 1,
144	      addParentData: false,
145	    },
146	    options.waitSecs ?? DEFAULT_WAIT_SECS,
147	    options.webhooks,
148	  );
149	}
