1	[{"name": "index.ts", "content": "// Edge function: auth-signup-creator (US-019 + US-020)
//
// Contract:
//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
//     → 200 {
//         token: string,
//         user_id: string,
//         role: 'creator',
//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
//       }
//       where Status is 'fresh' | 'refreshing' | 'failed'.
//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
//     → 422 { error: 'HANDLE_REQUIRED' }
//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
//
// Auth: none. This is how a creator obtains their first JWT, so the
// endpoint is verify_jwt=false at the gateway. The handler itself mints
// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
//
// Atomicity: the users + creator_profiles + social_links inserts run
// inside a single Postgres transaction via the public.auth_signup_creator
// RPC (us_019 migration). A failure on any insert rolls back the flow.
// Apify dispatch happens AFTER the RPC commits — per spec §5.1, a
// dispatch failure does NOT roll back the account (the user gets their
// JWT, metrics_status carries the per-platform outcome so the client can
// decide whether to retry later or surface a 'refreshing' placeholder).
//
// Handle normalization: leading '@' is stripped and whitespace trimmed
// before the RPC call. Handles are compared case-insensitively (citext),
// matching social_links.handle's column type.
//
// Apify dispatch (US-020): once the RPC commits, we look up the
// freshly-inserted social_links rows, then kick one or more Apify runs in
// parallel via Promise.allSettled — tiktok_profile for TikTok handles;
// ig_details and ig_posts for Instagram handles. Each run is registered
// with a per-run webhook pointing back at /functions/v1/apify-webhook so
// the receiver can persist the metric_snapshots row when Apify finishes.
// The wait window is APIFY_WAIT_SECS (60s); runs that come back
// SUCCEEDED within the window are reported as 'fresh' (the webhook will
// also arrive and be deduped via the unique index on run_id), otherwise
// 'refreshing' and the client polls. A thrown dispatch is 'failed'.
//
// Pre-refreshing rows: the spec calls for pre-creating metric_snapshots
// rows in status='refreshing' before the scrape so the client has
// something to read. That's deferred — the existing US-016..US-018 RPCs
// INSERT on webhook arrival via ON CONFLICT DO NOTHING, so the row
// appears only once Apify finishes. Tracked as a spec gap in progress.txt.
//
// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
// via a signup_attempts table (does not yet exist). Same status as the
// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.

import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2";
import { signJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";
import {
  type ApifyRunResult,
  type ApifyWebhookSpec,
  runInstagramDetails,
  runInstagramPosts,
  runTikTokProfile,
} from "../_shared/apify.ts";

const APIFY_WAIT_SECS = 60;
const APIFY_TERMINAL_EVENTS = [
  "ACTOR.RUN.SUCCEEDED",
  "ACTOR.RUN.FAILED",
  "ACTOR.RUN.TIMED_OUT",
  "ACTOR.RUN.ABORTED",
];

type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
type MetricsStatus = "fresh" | "refreshing" | "failed";

interface SignupRequest {
  username?: unknown;
  tiktok_handle?: unknown;
  instagram_handle?: unknown;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function isString(value: unknown): value is string {
  return typeof value === "string";
}

function normalizeHandle(value: unknown): string | null {
  if (!isString(value)) return null;
  const stripped = value.trim().replace(/^@+/, "").trim();
  return stripped.length > 0 ? stripped : null;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  let body: SignupRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const username =
    isString(body.username) && body.username.trim().length > 0
      ? body.username.trim()
      : null;
  const tiktokHandle = normalizeHandle(body.tiktok_handle);
  const instagramHandle = normalizeHandle(body.instagram_handle);

  if (!username) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }
  if (!tiktokHandle && !instagramHandle) {
    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data, error } = await supabase.rpc("auth_signup_creator", {
    p_username: username,
    p_tiktok_handle: tiktokHandle,
    p_instagram_handle: instagramHandle,
  });

  if (error) {
    console.error("auth_signup_creator rpc error", error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const result = data as { user_id?: string; error?: string } | null;
  if (result?.error === "USERNAME_TAKEN") {
    return jsonResponse(409, { error: "USERNAME_TAKEN" });
  }
  if (result?.error === "HANDLE_TAKEN") {
    return jsonResponse(409, { error: "HANDLE_TAKEN" });
  }
  if (!result?.user_id) {
    console.error("auth_signup_creator returned unexpected shape", result);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const userId = result.user_id;
  const sessionId = crypto.randomUUID();
  let token: string;
  try {
    token = await signJwt({
      sub: userId,
      role: "creator",
      session_id: sessionId,
    });
  } catch (err) {
    console.error("signJwt failed", err);
    return jsonResponse(500, { error: "JWT_ERROR" });
  }

  const metricsStatus = await dispatchApifyRuns({
    supabase,
    supabaseUrl,
    userId,
    tiktokHandle,
    instagramHandle,
  });

  return jsonResponse(200, {
    token,
    user_id: userId,
    role: "creator",
    metrics_status: metricsStatus,
  });
});

// Dispatches the Apify runs required for the freshly-created creator
// account. Returns a partial metrics_status map keyed by platform. If
// APIFY_KEY or APIFY_WEBHOOK_SECRET is unset (e.g. local dev without
// Apify credentials), logs a warning and returns {} — the account is
// still usable, the client just won't see any metrics until a future
// scrape picks it up. A failure to dispatch a single platform does not
// affect the others.
// deno-lint-ignore no-explicit-any -- supabase-js generic args differ between
// the createClient call above (inferred as public schema) and any helper
// import; typing this parameter loosely avoids a widening mismatch.
async function dispatchApifyRuns(params: {
  supabase: SupabaseClient<any, any, any>;
  supabaseUrl: string;
  userId: string;
  tiktokHandle: string | null;
  instagramHandle: string | null;
}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
  const { supabase, supabaseUrl, userId, tiktokHandle, instagramHandle } =
    params;
  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};

  const apifyKey = Deno.env.get("APIFY_KEY");
  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
  if (!apifyKey || !webhookSecret) {
    console.warn(
      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
    );
    return metricsStatus;
  }

  const { data: links, error: linksError } = await supabase
    .from("social_links")
    .select("id,platform")
    .eq("user_id", userId);
  if (linksError) {
    console.error("social_links lookup failed", linksError);
    return metricsStatus;
  }

  const linkRows = (links ?? []) as Array<{ id: string; platform: string }>;
  const tiktokLinkId = linkRows.find((l) => l.platform === "tiktok")?.id;
  const igLinkId = linkRows.find((l) => l.platform === "instagram")?.id;

  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
  const buildWebhook = (
    linkId: string,
    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
  ): ApifyWebhookSpec => ({
    eventTypes: APIFY_TERMINAL_EVENTS,
    requestUrl: webhookUrl,
    // Build a `resource` object field-by-field using dot-notation
    // placeholders. Apify only substitutes placeholders that appear inside
    // quoted JSON string values when `shouldInterpolateStrings: true`; bare
    // unquoted `{{var}}` substitutes the raw JSON value but can't round-trip
    // through JSON.stringify. Sticking to the quoted form keeps the template
    // valid JSON before substitution and readable by any linter.
    // apify-webhook/index.ts validResource requires id, defaultDatasetId,
    // status, and actId on the resource object.
    payloadTemplate: JSON.stringify({
      eventType: "{{eventType}}",
      resource: {
        id: "{{resource.id}}",
        defaultDatasetId: "{{resource.defaultDatasetId}}",
        status: "{{resource.status}}",
        actId: "{{resource.actId}}",
      },
      social_link_id: linkId,
      scrape_mode: scrapeMode,
      run_id: "{{resource.id}}",
      dataset_id: "{{resource.defaultDatasetId}}",
    }),
    headersTemplate: JSON.stringify({
      "X-Apify-Webhook-Secret": webhookSecret,
    }),
    shouldInterpolateStrings: true,
  });

  interface Task {
    key: MetricsKey;
    run: () => Promise<ApifyRunResult>;
  }
  const tasks: Task[] = [];
  if (tiktokHandle && tiktokLinkId) {
    tasks.push({
      key: "tiktok",
      run: () =>
        runTikTokProfile(tiktokHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(tiktokLinkId, "tiktok_profile")],
        }),
    });
  }
  if (instagramHandle && igLinkId) {
    tasks.push({
      key: "ig_details",
      run: () =>
        runInstagramDetails(instagramHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(igLinkId, "ig_details")],
        }),
    });
    tasks.push({
      key: "ig_posts",
      run: () =>
        runInstagramPosts(instagramHandle, {
          waitSecs: APIFY_WAIT_SECS,
          webhooks: [buildWebhook(igLinkId, "ig_posts")],
        }),
    });
  }

  if (tasks.length === 0) return metricsStatus;

  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
  settled.forEach((outcome, i) => {
    const key = tasks[i].key;
    if (outcome.status === "fulfilled") {
      // Apify's waitForFinish returns either SUCCEEDED (complete) or a
      // transitional status when the wait expires: READY, RUNNING,
      // TIMING-OUT, ABORTING. All four mean the webhook will still
      // fire and complete the snapshot, so they map to 'refreshing'.
      // Anything else (e.g. FAILED, ABORTED, TIMED-OUT terminal) is a
      // terminal non-success — 'failed'. The webhook receiver will
      // also write the failed row; the two converge via the run_id
      // unique index.
      const s = outcome.value.status;
      metricsStatus[key] = s === "SUCCEEDED"
        ? "fresh"
        : s === "READY" || s === "RUNNING" ||
            s === "TIMING-OUT" || s === "ABORTING"
        ? "refreshing"
        : "failed";
    } else {
      console.error(`apify ${key} dispatch failed`, outcome.reason);
      metricsStatus[key] = "failed";
    }
  });

  return metricsStatus;
}
"}, {"name": "../_shared/apify.ts", "content": "// Apify client wrapper for Marketify edge functions.
//
// Contract: runTikTokProfile(handle, { waitSecs?, webhooks? })    -> { runId, datasetId, status }
//           runInstagramDetails(handle, { waitSecs?, webhooks? }) -> { runId, datasetId, status }
//           runInstagramPosts(handle, { waitSecs?, webhooks? })   -> { runId, datasetId, status }
// Actors:   `clockworks/tiktok-scraper` (REST slug `clockworks~tiktok-scraper`),
//           `apify/instagram-scraper`  (REST slug `apify~instagram-scraper`).
//           Actor input shapes per docs/tech-architecture.md §3b / §3c.
// Endpoint: POST https://api.apify.com/v2/acts/<slug>/runs?token=<key>&waitForFinish=<secs>[&webhooks=<b64>].
//           The waitForFinish query parameter makes Apify block up to `waitSecs`
//           seconds before returning the run object, so callers can either parse
//           results inline (status=SUCCEEDED) or fall back to webhook-completed
//           delivery when the wait expires (status=RUNNING).
// Webhooks: per-run ad-hoc webhooks are passed as base64(JSON.stringify(specs))
//           in the `webhooks` query param per Apify's ad-hoc webhook API
//           (https://docs.apify.com/platform/integrations/webhooks/ad-hoc-webhooks).
//           Each spec includes eventTypes, requestUrl, and optional
//           payloadTemplate + headersTemplate (both already JSON-stringified
//           by the caller per docs/tech-architecture.md §3d), plus optional
//           shouldInterpolateStrings (required=true when payloadTemplate
//           wraps `{{placeholders}}` in quotes — Apify only substitutes
//           quoted placeholders under that flag; bare unquoted placeholders
//           always substitute as raw JSON).
// Secret:   APIFY_KEY env var (the Apify API token).
// Auth:     no inbound auth requirement — this module is a building block for
//           edge functions that have already verified JWT.

const APIFY_API_BASE = "https://api.apify.com/v2";

const TIKTOK_ACTOR_SLUG = "clockworks~tiktok-scraper";
const INSTAGRAM_ACTOR_SLUG = "apify~instagram-scraper";

const DEFAULT_WAIT_SECS = 60;

export interface ApifyRunResult {
  runId: string;
  datasetId: string;
  status: string;
}

export interface ApifyWebhookSpec {
  eventTypes: string[];
  requestUrl: string;
  payloadTemplate: string;
  headersTemplate?: string;
  shouldInterpolateStrings?: boolean;
}

export interface ApifyRunOptions {
  waitSecs?: number;
  webhooks?: ApifyWebhookSpec[];
}

function readApifyKey(): string {
  const k = Deno.env.get("APIFY_KEY");
  if (!k) throw new Error("APIFY_KEY is not set");
  return k;
}

async function startActorRun(
  slug: string,
  input: Record<string, unknown>,
  waitSecs: number,
  webhooks?: ApifyWebhookSpec[],
): Promise<ApifyRunResult> {
  if (!Number.isFinite(waitSecs) || waitSecs < 0) {
    throw new Error("waitSecs must be a non-negative finite number");
  }
  const url = new URL(`${APIFY_API_BASE}/acts/${slug}/runs`);
  url.searchParams.set("token", readApifyKey());
  url.searchParams.set("waitForFinish", String(Math.floor(waitSecs)));
  if (webhooks && webhooks.length > 0) {
    url.searchParams.set("webhooks", btoa(JSON.stringify(webhooks)));
  }

  const res = await fetch(url.toString(), {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(input),
  });

  if (!res.ok) {
    // Response body is intentionally not included — Apify sometimes echoes
    // the request URL (which carries the APIFY_KEY query param) inside error
    // payloads, and this error will land in edge-function logs.
    throw new Error(
      `Apify actor '${slug}' run failed: ${res.status} ${res.statusText}`,
    );
  }

  const payload = (await res.json()) as {
    data?: { id?: string; defaultDatasetId?: string; status?: string };
  };
  const data = payload.data;
  if (
    !data ||
    typeof data.id !== "string" ||
    typeof data.defaultDatasetId !== "string" ||
    typeof data.status !== "string"
  ) {
    throw new Error(
      `Apify actor '${slug}' returned malformed run payload`,
    );
  }
  return {
    runId: data.id,
    datasetId: data.defaultDatasetId,
    status: data.status,
  };
}

export async function runTikTokProfile(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    TIKTOK_ACTOR_SLUG,
    {
      profiles: [handle],
      resultsPerPage: 10,
      profileScrapeSections: ["videos"],
      profileSorting: "latest",
      excludePinnedPosts: true,
      shouldDownloadVideos: false,
      shouldDownloadCovers: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
    options.webhooks,
  );
}

export async function runInstagramDetails(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    INSTAGRAM_ACTOR_SLUG,
    {
      directUrls: [`https://www.instagram.com/${handle}/`],
      resultsType: "details",
      resultsLimit: 1,
      addParentData: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
    options.webhooks,
  );
}

export async function runInstagramPosts(
  handle: string,
  options: ApifyRunOptions = {},
): Promise<ApifyRunResult> {
  if (!handle) throw new Error("handle is required");
  return await startActorRun(
    INSTAGRAM_ACTOR_SLUG,
    {
      directUrls: [`https://www.instagram.com/${handle}/`],
      resultsType: "posts",
      resultsLimit: 10,
      addParentData: false,
    },
    options.waitSecs ?? DEFAULT_WAIT_SECS,
    options.webhooks,
  );
}
"}, {"name": "../_shared/cors.ts", "content": "// Shared CORS headers for every Marketify edge function.
//
// Contract: exports `corsHeaders` (Record<string, string>) to splat into
//           every edge function's response and a pre-flight short-circuit.
// Auth:     n/a — the browser reads these before the request runs.
//
// `*` origin is safe here: edge functions authenticate via the
// Authorization: Bearer <marketify_jwt> header, not cookies, so there is no
// ambient-credential risk to guard against with a narrower origin allowlist.

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};
"}, {"name": "../_shared/jwt.ts", "content": "// Custom JWT helper for Marketify edge functions.
//
// Contract: signJwt({ sub, role, session_id }, { ttlSeconds? }) -> compact JWT.
//           verifyJwt(token) -> parsed claims or throws.
// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
// Secret: MARKETIFY_JWT_SECRET env var — this is OUR signing key, deliberately
//         separate from Supabase's built-in JWT secret. Every `/auth/*` edge
//         function mints tokens here; RLS policies read `sub` and `role` via
//         `auth.jwt()`. `session_id` feeds the denylist lookup in §15c.
// Auth:   no inbound auth requirement — this module is a building block.

export type UserRole = "creator" | "lister";

export interface JwtClaims {
  sub: string;
  role: UserRole;
  session_id: string;
  iat: number;
  exp: number;
}

export interface SignInput {
  sub: string;
  role: UserRole;
  session_id: string;
}

export interface SignOptions {
  ttlSeconds?: number;
}

const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
const encoder = new TextEncoder();
const decoder = new TextDecoder();

function readSecret(): string {
  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
  return s;
}

function base64UrlEncode(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

function base64UrlDecode(input: string): Uint8Array {
  const rem = input.length % 4;
  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
    .replaceAll("-", "+")
    .replaceAll("_", "/");
  let raw: string;
  try {
    raw = atob(b64);
  } catch {
    throw new Error("Malformed JWT");
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
  return out;
}

async function importKey(
  secret: string,
  usages: KeyUsage[],
): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );
}

export async function signJwt(
  input: SignInput,
  options: SignOptions = {},
): Promise<string> {
  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
  if (!Number.isFinite(ttl) || ttl <= 0) {
    throw new Error("ttlSeconds must be a positive finite number");
  }
  if (input.role !== "creator" && input.role !== "lister") {
    throw new Error("role must be 'creator' or 'lister'");
  }

  const now = Math.floor(Date.now() / 1000);
  const payload: JwtClaims = {
    sub: input.sub,
    role: input.role,
    session_id: input.session_id,
    iat: now,
    exp: now + ttl,
  };

  const headerB64 = base64UrlEncode(
    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
  );
  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${headerB64}.${payloadB64}`;

  const key = await importKey(readSecret(), ["sign"]);
  const sig = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(signingInput),
  );
  const sigB64 = base64UrlEncode(new Uint8Array(sig));

  return `${signingInput}.${sigB64}`;
}

export async function verifyJwt(token: string): Promise<JwtClaims> {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Malformed JWT");
  const [headerB64, payloadB64, sigB64] = parts;

  let header: { alg?: string };
  try {
    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
  } catch {
    throw new Error("Malformed JWT");
  }
  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");

  const key = await importKey(readSecret(), ["verify"]);
  const ok = await crypto.subtle.verify(
    "HMAC",
    key,
    base64UrlDecode(sigB64),
    encoder.encode(`${headerB64}.${payloadB64}`),
  );
  if (!ok) throw new Error("Bad signature");

  let payload: Partial<JwtClaims>;
  try {
    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
  } catch {
    throw new Error("Malformed JWT");
  }

  if (
    typeof payload.sub !== "string" || payload.sub.length === 0 ||
    (payload.role !== "creator" && payload.role !== "lister") ||
    typeof payload.session_id !== "string" ||
    payload.session_id.length === 0 ||
    typeof payload.iat !== "number" ||
    typeof payload.exp !== "number"
  ) {
    throw new Error("JWT missing required claims");
  }

  const now = Math.floor(Date.now() / 1000);
  if (payload.exp <= now) throw new Error("JWT expired");
  if (payload.iat > now + 60) throw new Error("JWT iat in the future");

  return payload as JwtClaims;
}
"}]

